import logging
import json
import os
import azure.functions as func

# Define allowed origins explicitly rather than using wildcard
# This prevents unauthorized domains from making cross-origin requests
ALLOWED_ORIGINS = os.environ.get(
    "ALLOWED_ORIGINS",
    "http://localhost:3000,http://localhost:5173,http://localhost:8080"
).split(",")

ALLOWED_METHODS = ["GET", "POST", "PUT", "DELETE", "OPTIONS"]
ALLOWED_HEADERS = ["Content-Type", "Authorization", "X-Requested-With"]
MAX_AGE = "3600"


def get_cors_origin(req: func.HttpRequest) -> str:
    """
    Validate the Origin header against the allowlist.
    Returns the origin if allowed, otherwise returns empty string.
    
    SECURITY NOTE: Using '*' (wildcard) for CORS is insecure because:
    - It allows any website to make authenticated requests to your API
    - It can lead to data exfiltration via malicious third-party sites
    - It undermines the Same-Origin Policy browser protection
    - Credentials (cookies, auth headers) behavior varies and can be exploited
    
    Instead, we explicitly allowlist known development and staging origins.
    """
    request_origin = req.headers.get("Origin", "")
    
    # Strip whitespace from configured origins for comparison
    stripped_allowed = [o.strip() for o in ALLOWED_ORIGINS if o.strip()]
    
    if request_origin in stripped_allowed:
        return request_origin
    
    return ""


def add_cors_headers(headers: dict, allowed_origin: str) -> dict:
    """Add CORS headers to response, only if origin is allowed."""
    if allowed_origin:
        headers["Access-Control-Allow-Origin"] = allowed_origin
        headers["Access-Control-Allow-Methods"] = ", ".join(ALLOWED_METHODS)
        headers["Access-Control-Allow-Headers"] = ", ".join(ALLOWED_HEADERS)
        headers["Access-Control-Max-Age"] = MAX_AGE
        # Vary header is important when Access-Control-Allow-Origin is not *
        headers["Vary"] = "Origin"
        # Only set Allow-Credentials when we have a specific origin (never with *)
        headers["Access-Control-Allow-Credentials"] = "true"
    return headers


def add_security_headers(headers: dict) -> dict:
    """Add standard security headers to all responses."""
    headers["X-Content-Type-Options"] = "nosniff"
    headers["X-Frame-Options"] = "DENY"
    headers["X-XSS-Protection"] = "1; mode=block"
    headers["Referrer-Policy"] = "strict-origin-when-cross-origin"
    headers["Cache-Control"] = "no-store"
    headers["Content-Security-Policy"] = "default-src 'none'; frame-ancestors 'none'"
    headers["Strict-Transport-Security"] = "max-age=31536000; includeSubDomains"
    return headers


def create_response(
    req: func.HttpRequest,
    body: dict,
    status_code: int = 200
) -> func.HttpResponse:
    """Create an HTTP response with proper CORS and security headers."""
    headers = {}
    allowed_origin = get_cors_origin(req)
    headers = add_cors_headers(headers, allowed_origin)
    headers = add_security_headers(headers)
    headers["Content-Type"] = "application/json"
    
    return func.HttpResponse(
        body=json.dumps(body),
        status_code=status_code,
        headers=headers
    )


def validate_request_content_type(req: func.HttpRequest) -> bool:
    """Validate that POST/PUT requests have proper Content-Type."""
    if req.method in ("POST", "PUT"):
        content_type = req.headers.get("Content-Type", "")
        if "application/json" not in content_type:
            return False
    return True


# Main function entry point
app = func.FunctionApp()


@app.route(route="preflight", methods=["OPTIONS"], auth_level=func.AuthLevel.ANONYMOUS)
def handle_preflight(req: func.HttpRequest) -> func.HttpResponse:
    """
    Handle CORS preflight OPTIONS requests.
    This must be anonymous since browsers don't send auth on preflight.
    """
    logging.info("Handling CORS preflight request")
    
    headers = {}
    allowed_origin = get_cors_origin(req)
    
    if not allowed_origin:
        logging.warning(
            "Preflight request from disallowed origin: %s",
            req.headers.get("Origin", "unknown")
        )
        return func.HttpResponse(status_code=403, headers=add_security_headers({}))
    
    headers = add_cors_headers(headers, allowed_origin)
    headers = add_security_headers(headers)
    
    return func.HttpResponse(status_code=204, headers=headers)


